verification.command:
set -e
s=$(git show HEAD:.agent/product_spec_005.md | python3 -c "import yaml,sys; print(yaml.safe_load(sys.stdin.read().split('---')[1])['status'])")
[ "$s" = "draft" ] || { echo "expected HEAD spec status 'draft', got '$s'"; exit 1; }
git show HEAD:docs/planning/ROADMAP.md | grep -Eq 'Track 2 is the recommended phase 005' || { echo 'stale ROADMAP sentence unexpectedly absent at HEAD'; exit 1; }
n=$(git show HEAD:docs/planning/ROADMAP.md | python3 -c "import yaml,sys; print(len(yaml.safe_load(sys.stdin.read().split('---')[1]).get('change_log',[])))")
[ "$n" -eq 4 ] || { echo "expected HEAD ROADMAP change_log length 4, got $n"; exit 1; }
v=$(git show HEAD:docs/planning/DEBT.md | python3 -c "import yaml,sys; print(yaml.safe_load(sys.stdin.read().split('---')[1])['version'])")
[ "$v" = "0.11.0" ] || { echo "expected HEAD DEBT.md version 0.11.0, got $v"; exit 1; }
git show HEAD:docs/planning/DEBT.md | grep -Eq 'NDEBT-019|NDEBT-020' && { echo 'NDEBT-019/020 unexpectedly already present at HEAD'; exit 1; }
echo PASS

f=.agent/evidence/045-release-readiness-checklist.md
test -f "$f" || { echo 'checklist missing'; exit 1; }
n=$(grep -c . "$f")
[ "$n" -eq 8 ] || { echo "expected exactly 8 non-blank lines, got $n"; exit 1; }
for i in 1 2 3 4 5 6 7 8; do
  c=$(grep -cE "^${i}\." "$f")
  [ "$c" -eq 1 ] || { echo "item ${i} label must appear exactly once, found ${c}"; exit 1; }
done
grep -qxF '7. Human sign-off complete: PENDING -- human-gated (H-FRAMEWORK-RELEASE)' "$f" || { echo 'item 7 is not byte-identical to the pinned literal'; exit 1; }
grep -qxF '8. Immutable tag published: PENDING -- human-gated (H-FRAMEWORK-RELEASE)' "$f" || { echo 'item 8 is not byte-identical to the pinned literal'; exit 1; }
h=$(sha256sum "$f" | awk '{print $1}'); rc=$?
[ "$rc" -eq 0 ] || { echo 'sha256sum failed'; exit 1; }
[ "$h" = "06f266c06abd9b3793477771de265698dbec0a00761c6d81818decbc7e31b5ea" ] || { echo "checklist content does not match the pinned exact byte content (got $h)"; exit 1; }
echo PASS

n=$(awk '/^## Open/{f=1} /^## Resolved/{f=0} f' docs/planning/DEBT.md | grep '^| NDEBT' | grep -icE '\| *(High|Critical) *\|'); rc=$?
[ "$n" -eq 0 ] || { echo "found $n open High/Critical debt item(s) -- release exit criterion 6 violated"; exit 1; }
echo PASS
